"""API routes for Docuflow."""
import logging
from flask import Blueprint, request, jsonify
from werkzeug.utils import secure_filename as werkzeug_secure_filename

logger = logging.getLogger(__name__)

docuflow_bp = Blueprint('docuflow', __name__)


@docuflow_bp.route('/api/v1/documents/upload', methods=['POST'])
def upload_document():
    """Handle document upload.

    Expects multipart/form-data with a 'file' field.

    Returns:
        JSON with document metadata on success, error on failure.
    """
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400

    uploaded_file = request.files['file']
    if uploaded_file.filename == '':
        return jsonify({'error': 'Empty filename'}), 400

    try:
        from services.upload import UploadService

        upload_service = UploadService()

        result = upload_service.process_upload(
            file_data=uploaded_file.read(),
            filename=uploaded_file.filename,
            content_type=uploaded_file.content_type,
        )

        return jsonify({
            'message': 'Document uploaded successfully',
            'document': result.to_dict()
        }), 201

    except FilenameValidationError as e:
        logger.warning(f'Filename validation failed: {e}')
        return jsonify({
            'error': 'Invalid filename',
            'details': str(e)
        }), 400

    except FileTooLargeError as e:
        logger.warning(f'File size validation failed: {e}')
        return jsonify({
            'error': 'File too large',
            'details': str(e)
        }), 400

    except InvalidFileTypeError as e:
        logger.warning(f'File type validation failed: {e}')
        return jsonify({
            'error': 'Invalid file type',
            'details': str(e)
        }), 400

    except UploadError as e:
        logger.error(f'Upload failed: {e}')
        return jsonify({
            'error': 'Upload failed',
            'details': str(e)
        }), 500

    except Exception as e:
        logger.error(f'Unexpected upload error: {e}', exc_info=True)
        return jsonify({'error': 'Internal server error'}), 500


